"use strict";const hamburgerBtn=document.querySelector(".hamburger-btn"),mainNav=document.querySelector("#main-nav"),mainNavList=document.querySelector(".main-nav-list");hamburgerBtn.addEventListener("click",()=>{let e=mainNav.classList.toggle("nav-open");hamburgerBtn.setAttribute("aria-expanded",e?"true":"false")}),mainNavList.addEventListener("click",e=>{"A"===e.target.tagName&&(mainNav.classList.remove("nav-open"),hamburgerBtn.setAttribute("aria-expanded","false"))});